SELECT utterance
FROM utterances
WHERE utterance_id = 0;

SELECT COUNT(feedback_id) AS feedback_count
FROM intent_feedback
WHERE intent_id = 0;

SELECT COUNT(utterance_id) AS utterance_count
FROM utterances
WHERE user_id = 1;

SELECT intent_id
FROM intent_usage
ORDER BY utterance_count DESC;

SELECT utterance_count AS trigger_count
FROM intent_usage
WHERE intent_id = 0;

SELECT golden_intent
FROM intents
WHERE category = 'product inquiry';

SELECT AVG(rating) AS average_rating
FROM feedback
WHERE user_id = 1;
